// Catch-all for unknown /api/* paths. Concrete API routes (search, ask, openapi,
// health, md, well-known/*) are more specific and take precedence; this only
// fires for paths that match nothing, returning a structured RFC 9457 error
// instead of an HTML 404 so agents get machine-readable recovery guidance.
export const dynamic = "force-dynamic";

async function notFound(
	_req: Request,
	{ params }: { params: Promise<{ path?: string[] }> },
): Promise<Response> {
	const { path } = await params;
	const instance = `/api/${(path ?? []).join("/")}`;
	return problemResponse({
		type: "https://orchestkit.yonyon.ai/docs/reference",
		title: "API endpoint not found",
		status: 404,
		detail: `No API endpoint matches ${instance}. See the API catalog at /.well-known/api-catalog or the OpenAPI spec at /api/openapi.`,
		instance,
	});
}

export const GET = notFound;
export const POST = notFound;
export const PUT = notFound;
export const PATCH = notFound;
export const DELETE = notFound;
